@click.group(cls=FRR_AbbreviationGroup, name='bfd',)
def frr_clear_bfd(clear_bfd_='clear_bfd'):
    """Bidirection Forwarding Detection"""
    global COMMON_DATA_MAP
    #ctx = click.get_current_context()
    #config_db = ValidatedConfigDBConnector(db.cfgdb)
    
    data_gen = {}
    name = frr_clear_bfd.name
    
    if 'VIEW_NODE|clear_bfd' not in COMMON_DATA_MAP:
        COMMON_DATA_MAP['VIEW_NODE|clear_bfd'] = {}

    for key, val in data_gen.items():
        if key.islower() and key in COMMON_DATA_MAP['VIEW_NODE|clear_bfd']:
            key = key.upper()
        COMMON_DATA_MAP['VIEW_NODE|clear_bfd'][key] = val
    
    # set VIEW_NODE -> clear_bfd table
    COMMON_DATA_MAP['VIEW_NODE'] = 'clear_bfd'
    pass


